class Solution {
    public int racecar(int target) {
        int[] dp = new int[target + 1];
        for (int i = 1; i <= target; i++) {
            dp[i] = Integer.MAX_VALUE;
            int m = 1, p = 1;
            for (int j = 0; p < i; j++, m *= 2, p += m) {
                dp[i] = Math.min(dp[i], j + 1 + (i - p > 0 ? dp[i - p] : 0));
                if (p > i) {
                    dp[i] = Math.min(dp[i], j + 1 + dp[p - i] + 1);
                }
            }
        }
        return dp[target];
    }
}
